<?php namespace Database\Seeders; use Illuminate\Database\Seeder; use Illuminate\Support\Facades\DB; class DataMigrationSeeder extends Seeder { public function run(): void { DB::transaction(function () { $this->seedRolesAndPermissions(); $this->seedCaseConfiguration(); }); } protected function seedRolesAndPermissions(): void { $roles = ['admin', 'lawyer', 'client']; foreach ($roles as $role) { \App\Models\Role::updateOrCreate(['name' => $role], ['guard_name' => 'web']); } } protected function seedCaseConfiguration(): void { $types = ['Civil', 'Criminal', 'Commercial', 'Family']; foreach ($types as $type) { \App\Models\CaseType::updateOrCreate(['name' => $type], ['is_active' => true]); } $statuses = ['Pending', 'In Progress', 'Closed', 'Archived']; foreach ($statuses as $status) { \App\Models\CaseStatus::updateOrCreate(['name' => $status], ['color_code' => '#000000']); } } }